Решение: fn sum_array(nums: Vec<i32>) -> i32 { nums.iter().sum() }
Отдельные тесты: fn test_empty() { assert_eq!(sum_array(vec![]), 0); }
fn test_single() { assert_eq!(sum_array(vec![5]), 5); }

